import React, { useState } from "react";

const SocialMediaPractice = () => {
  const [userChoice, setUserChoice] = useState("");
  const [submitted, setSubmitted] = useState(false);
  const [feedback, setFeedback] = useState("");

  const handleSubmit = () => {
    let message = "";
    if (userChoice === "not_safe") {
      message = "✅ Great job! The house number and location tag reveal your address.";
    } else if (userChoice === "safe") {
      message = "❌ Oops! This post shows your house number and location — not safe!";
    } else {
      message = "🤔 Not sure? It's always safer to avoid posting sensitive info.";
    }
    setFeedback(message);
    setSubmitted(true);
  };

  return (
    <div className="min-h-screen w-full bg-gradient-to-br from-blue-50 to-blue-100 flex items-center justify-center px-4 py-8">
      <div className="w-full max-w-md bg-white rounded-xl shadow-md p-6 space-y-6">
        {/* 标题 */}
        <div className="text-xl font-bold flex items-center space-x-2 text-gray-800">
          <span className="text-2xl">📱</span>
          <h1>Social Media Safety Check</h1>
        </div>

        {/* 提示信息 */}
        <div className="flex items-start space-x-3">
          <div className="text-xl">🤖</div>
          <div className="bg-blue-50 rounded-xl px-4 py-3 text-sm leading-relaxed shadow-inner">
            Can you spot the privacy risks in this social media post?
          </div>
        </div>

        {/* 图片容器 - 修改了图片尺寸 */}
        <div className="flex justify-center border-2 border-dashed border-gray-200 rounded-lg p-2 bg-gray-50">
          <img
            src="/images/socialmedia/1.jpg"
            alt="Example social media post"
            className="w-full max-w-xs h-auto object-contain rounded-md shadow-sm"
          />
        </div>

        {/* 选项列表 */}
        {!submitted ? (
          <div className="space-y-4">
            <p className="text-sm font-medium text-gray-700">Is this post safe to share?</p>
            <div className="space-y-3">
              <label className="flex items-center space-x-3 p-3 bg-gray-50 rounded-lg hover:bg-blue-50 cursor-pointer">
                <input 
                  type="radio" 
                  name="choice" 
                  value="safe" 
                  onChange={(e) => setUserChoice(e.target.value)}
                  className="h-4 w-4 text-blue-600"
                />
                <span>✅ Safe to post</span>
              </label>
              
              <label className="flex items-center space-x-3 p-3 bg-gray-50 rounded-lg hover:bg-blue-50 cursor-pointer">
                <input 
                  type="radio" 
                  name="choice" 
                  value="not_safe" 
                  onChange={(e) => setUserChoice(e.target.value)}
                  className="h-4 w-4 text-blue-600"
                />
                <span>⚠️ Not safe (contains private info)</span>
              </label>
              
              <label className="flex items-center space-x-3 p-3 bg-gray-50 rounded-lg hover:bg-blue-50 cursor-pointer">
                <input 
                  type="radio" 
                  name="choice" 
                  value="not_sure" 
                  onChange={(e) => setUserChoice(e.target.value)}
                  className="h-4 w-4 text-blue-600"
                />
                <span>🤔 I'm not sure</span>
              </label>
            </div>
            
            <button
              onClick={handleSubmit}
              disabled={!userChoice}
              className="w-full mt-4 bg-blue-600 text-white py-2 rounded-lg hover:bg-blue-700 disabled:bg-gray-400 transition-colors"
            >
              Submit Answer
            </button>
          </div>
        ) : (
          <div className="flex items-start space-x-3">
            <div className="text-xl">🤖</div>
            <div className="bg-blue-50 rounded-xl px-4 py-3 shadow-inner">
              <p className="font-medium">{feedback}</p>
              <p className="text-sm text-gray-600 mt-2">
                🧠 Pro Tip: Avoid posting real-time location check-ins or visible house numbers.
              </p>
              <button 
                onClick={() => {
                  setSubmitted(false);
                  setUserChoice("");
                }}
                className="mt-3 text-sm text-blue-600 hover:underline"
              >
                Try another example
              </button>
            </div>
          </div>
        )}
      </div>
    </div>
  );
};

export default SocialMediaPractice;
